interface SecureTokenStore {
    fun storeToken(alias: String, rawToken: String)
    fun getToken(alias: String): String?
    fun deleteToken(alias: String)
}

@RequiresApi(Build.VERSION_CODES.M)
class AndroidKeystoreTokenStore(
    private val context: Context
) : SecureTokenStore {

    private val prefs = context.applicationContext.getSharedPreferences("secure_payment_store", Context.MODE_PRIVATE)
    private val keyAliasPrefix = "payment_aes_key_"
    private val secureRandom = SecureRandom()

    override fun storeToken(alias: String, rawToken: String) {
        require(alias.isNotBlank()) { "alias is required" }
        require(rawToken.isNotBlank()) { "rawToken is required" }
        val key = getOrCreateKey(alias)
        val iv = ByteArray(12).also { secureRandom.nextBytes(it) }
        val cipher = Cipher.getInstance("AES/GCM/NoPadding")
        cipher.init(Cipher.ENCRYPT_MODE, key, GCMParameterSpec(128, iv))
        val encrypted = cipher.doFinal(rawToken.toByteArray(Charsets.UTF_8))
        val payload = iv + encrypted
        prefs.edit().putString(alias, payload.encodeBase64()).apply()
    }

    override fun getToken(alias: String): String? {
        require(alias.isNotBlank()) { "alias is required" }
        val stored = prefs.getString(alias, null) ?: return null
        val payload = stored.decodeBase64()
        require(payload.size > 12) { "Corrupted encrypted payload" }
        val iv = payload.copyOfRange(0, 12)
        val ciphertext = payload.copyOfRange(12, payload.size)
        val key = getOrCreateKey(alias)
        val cipher = Cipher.getInstance("AES/GCM/NoPadding")
        cipher.init(Cipher.DECRYPT_MODE, key, GCMParameterSpec(128, iv))
        return cipher.doFinal(ciphertext).toString(Charsets.UTF_8)
    }

    override fun deleteToken(alias: String) {
        require(alias.isNotBlank()) { "alias is required" }
        prefs.edit().remove(alias).apply()
        val keyStore = KeyStore.getInstance("AndroidKeyStore").apply { load(null) }
        if (keyStore.containsAlias(fullAlias(alias))) {
            keyStore.deleteEntry(fullAlias(alias))
        }
    }

    private fun getOrCreateKey(alias: String): SecretKey {
        val fullAlias = fullAlias(alias)
        val keyStore = KeyStore.getInstance("AndroidKeyStore").apply { load(null) }
        val existing = keyStore.getKey(fullAlias, null)
        if (existing is SecretKey) return existing

        val keyGenerator = KeyGenerator.getInstance("AES", "AndroidKeyStore")
        val spec = android.security.keystore.KeyGenParameterSpec.Builder(
            fullAlias,
            android.security.keystore.KeyProperties.PURPOSE_ENCRYPT or
                android.security.keystore.KeyProperties.PURPOSE_DECRYPT
        )
            .setBlockModes(android.security.keystore.KeyProperties.BLOCK_MODE_GCM)
            .setEncryptionPaddings(android.security.keystore.KeyProperties.ENCRYPTION_PADDING_NONE)
            .setRandomizedEncryptionRequired(true)
            .setUserAuthenticationRequired(false)
            .build()
        keyGenerator.init(spec)
        return keyGenerator.generateKey()
    }

    private fun fullAlias(alias: String): String = keyAliasPrefix + alias
}

class PaymentIntegritySigner(secretKey: ByteArray) {
    private val key = secretKey.copyOf()

    fun sign(payload: String): String {
        val mac = Mac.getInstance("HmacSHA256")
        val secret = javax.crypto.spec.SecretKeySpec(key, "HmacSHA256")
        mac.init(secret)
        return mac.doFinal(payload.toByteArray(Charsets.UTF_8)).encodeBase64()
    }

    fun verify(payload: String, signature: String): Boolean {
        return try {
            val expected = sign(payload).decodeBase64()
            val actual = signature.decodeBase64()
            constantTimeEquals(expected, actual)
        } catch (_: IllegalArgumentException) {
            false
        }
    }

    private fun constantTimeEquals(a: ByteArray, b: ByteArray): Boolean {
        if (a.size != b.size) return false
        var result = 0
        for (i in a.indices) {
            result = result or (a[i].toInt() xor b[i].toInt())
        }
        return result == 0
    }
}

interface PaymentGateway {
    fun authorize(request: PaymentRequest): PaymentResult
    fun capture(transactionId: String): PaymentResult
}

class InMemoryPaymentGateway : PaymentGateway {
    private val transactions = ConcurrentHashMap<String, PaymentStatus>()

    override fun authorize(request: PaymentRequest): PaymentResult {
        validateSensitiveInput(request)
        val transactionId = UUID.randomUUID().toString()
        transactions[transactionId] = PaymentStatus.AUTHORIZED
        return PaymentResult(
            transactionId = transactionId,
            status = PaymentStatus.AUTHORIZED,
            approvalCode = randomApprovalCode(),
            message = "Authorized"
        )
    }

    override fun capture(transactionId: String): PaymentResult {
        require(transactionId.isNotBlank()) { "transactionId is required" }
        val current = transactions[transactionId]
        return if (current == PaymentStatus.AUTHORIZED) {
            transactions[transactionId] = PaymentStatus.CAPTURED
            PaymentResult(
                transactionId = transactionId,
                status = PaymentStatus.CAPTURED,
                approvalCode = randomApprovalCode(),
                message = "Captured"
            )
        } else {
            PaymentResult(
                transactionId = transactionId,
                status = PaymentStatus.FAILED,
                approvalCode = null,
                message = "Transaction not authorized"
            )
        }
    }

    private fun validateSensitiveInput(request: PaymentRequest) {
        require(request.paymentToken.length in 8..4096) { "Invalid payment token length" }
    }

    private fun randomApprovalCode(): String {
        val chars = "ABCDEFGHJKLMNPQRSTUVWXYZ23456789"
        val random = SecureRandom()
        return buildString(8) {
            repeat(8) { append(chars[random.nextInt(chars.length)]) }
        }
    }
}

class WalletService {
    private val balances = ConcurrentHashMap<String, Money>()
    private val processedByIdempotency = ConcurrentHashMap<String, WalletTransactionResult>()

    @Synchronized
    fun applyTransaction(transaction: WalletTransaction): WalletTransactionResult {
        val existing = processedByIdempotency[transaction.idempotencyKey]
        if (existing != null) return existing

        val current = balances[transaction.walletId] ?: Money(BigDecimal.ZERO, transaction.money.currency)
        require(current.currency == transaction.money.currency) { "Currency mismatch" }

        val newAmount = when (transaction.type) {
            PaymentType.WALLET_DEBIT -> {
                require(current.amount >= transaction.money.amount) { "Insufficient funds" }
                current.amount.subtract(transaction.money.amount)
            }
            PaymentType.WALLET_CREDIT -> current.amount.add(transaction.money.amount)
            else -> error("Unsupported wallet operation")
        }

        val updated = Money(newAmount, current.currency)
        balances[transaction.walletId] = updated

        val result = WalletTransactionResult(
            transactionId = UUID.randomUUID().toString(),
            balance = updated,
            status = PaymentStatus.CAPTURED,
            message = "Wallet transaction applied"
        )
        processedByIdempotency[transaction.idempotencyKey] = result
        return result
    }

    fun getBalance(walletId: String, currency: String): Money {
        require(walletId.isNotBlank()) { "walletId is required" }
        require(currency.matches(Regex("^[A-Z]{3}$"))) { "Invalid currency" }
        return balances[walletId] ?: Money(BigDecimal.ZERO, currency)
    }
}

class PaymentProcessor(
    private val paymentGateway: PaymentGateway,
    private val walletService: WalletService,
    private val tokenStore: SecureTokenStore? = null
) {
    fun processInAppPurchase(request: PaymentRequest): PaymentResult {
        PaymentModulePolicy.assertSupportedDevice()
        require(request.type == PaymentType.IN_APP_PURCHASE) { "Invalid payment type for in-app purchase" }
        val sanitized = request.copy(paymentToken = request.paymentToken.trim())
        tokenStore?.storeToken("txn_${sanitized.referenceId}", sanitized.paymentToken)
        val authorized = paymentGateway.authorize(sanitized)
        return if (authorized.status == PaymentStatus.AUTHORIZED) {
            paymentGateway.capture(authorized.transactionId)
        } else {
            authorized
        }
    }

    fun processWalletTransaction(transaction: WalletTransaction): WalletTransactionResult {
        PaymentModulePolicy.assertSupportedDevice()
        return walletService.applyTransaction(transaction)
    }
}

